import React, { useState } from 'react';
import { Search } from 'lucide-react';

const SearchBar = ({ onSearch }) => {
    const [location, setLocation] = useState('');
    const [checkIn, setCheckIn] = useState('');
    const [checkOut, setCheckOut] = useState('');
    const [guests, setGuests] = useState(1);

    const handleSubmit = (e) => {
        e.preventDefault();
        onSearch({ location, checkIn, checkOut, guests });
    };

    return (
        <div className="bg-white rounded-full shadow-lg p-2 max-w-4xl mx-auto border border-gray-200">
            <form onSubmit={handleSubmit} className="flex flex-col md:flex-row items-center divide-y md:divide-y-0 md:divide-x divide-gray-200">

                <div className="px-6 py-2 w-full md:w-1/3 hover:bg-gray-50 rounded-full transition-colors cursor-pointer">
                    <label className="block text-xs font-bold text-gray-800 uppercase tracking-wider">Location</label>
                    <input
                        type="text"
                        placeholder="Where are you going?"
                        className="w-full bg-transparent border-none p-0 text-gray-600 placeholder-gray-400 focus:ring-0 text-sm truncate"
                        value={location}
                        onChange={(e) => setLocation(e.target.value)}
                    />
                </div>

                <div className="px-6 py-2 w-full md:w-1/4 hover:bg-gray-50 transition-colors cursor-pointer">
                    <label className="block text-xs font-bold text-gray-800 uppercase tracking-wider">Check in</label>
                    <input
                        type="date"
                        className="w-full bg-transparent border-none p-0 text-gray-600 focus:ring-0 text-sm"
                        value={checkIn}
                        onChange={(e) => setCheckIn(e.target.value)}
                    />
                </div>

                <div className="px-6 py-2 w-full md:w-1/4 hover:bg-gray-50 transition-colors cursor-pointer">
                    <label className="block text-xs font-bold text-gray-800 uppercase tracking-wider">Check out</label>
                    <input
                        type="date"
                        className="w-full bg-transparent border-none p-0 text-gray-600 focus:ring-0 text-sm"
                        value={checkOut}
                        onChange={(e) => setCheckOut(e.target.value)}
                    />
                </div>

                <div className="px-6 py-2 w-full md:w-1/6 flex items-center justify-between hover:bg-gray-50 rounded-r-full transition-colors">
                    <div className="flex-1">
                        <label className="block text-xs font-bold text-gray-800 uppercase tracking-wider">Guests</label>
                        <input
                            type="number"
                            min="1"
                            className="w-full bg-transparent border-none p-0 text-gray-600 focus:ring-0 text-sm"
                            value={guests}
                            onChange={(e) => setGuests(e.target.value)}
                        />
                    </div>
                    <button type="submit" className="bg-rose-500 hover:bg-rose-600 text-white p-3 rounded-full shadow-md transition-all transform hover:scale-105 ml-2">
                        <Search className="w-5 h-5" />
                    </button>
                </div>

            </form>
        </div>
    );
};

export default SearchBar;
